SELECT num_elements
FROM partitions
WHERE partition_number = 0;

SELECT partition_number
FROM partitions
WHERE num_elements > 100000;

SELECT cpu_usage
FROM partition_performance
WHERE partition_id = 1 AND simulation_run_id = 1;

SELECT metric_name, AVG(metric_value) AS average_value
FROM simulation_metrics
GROUP BY metric_name;

SELECT AVG(num_partitions) AS average_partitions
FROM (
  SELECT simulation_id, COUNT(partition_id) AS num_partitions
  FROM partitions
  GROUP BY simulation_id
) AS partition_counts;

SELECT MAX(cpu_usage)
  FROM partition_performance
  WHERE partition_id = 1 AND simulation_run_id = 1;

SELECT partition_number
FROM partitions
WHERE num_elements = (SELECT MAX(num_elements) FROM partitions);

SELECT simulation_name, status
FROM simulations
ORDER BY simulation_name;
